children.text:
@font-face {
    font-family: 'Ahem';
    src: url('file:///Users/henryluo/Projects/lambda-test/layout/data/support/ahem3.ttf') format('truetype');
    font-weight: normal;
    font-style: normal;
}

body {
    margin-left: 0;
}
.container {
  width: 400px;
  text-align: center;
  font-family: Ahem;
  font-size: 20px;
  line-height: 1em;
}
#test {
    color: green;
}
#test-float-left {
  shape-outside: polygon(0 0, 1000px 1000px, 0 1000px);
  float: left;
  width: 200px;
  height: 200px;
}
#test-float-right {
  shape-outside: polygon(200px 0, 200px 200px, 0 200px);
  float: right;
  width: 200px;
  height: 200px;
}
#failure-container {
    color: red;
    z-index: -1;
}
#test, #failure-container {
    position: absolute;
    top: 60px;
}
.line {
    height: 20px;
}
#bottom {
    position: absolute;
    top: 200px;
}
#left-triangle, #right-triangle {
    position: absolute;
    top: 60px;
    width: 200px;
    height: 200px;
    background-color: lightblue;
}
#left-triangle {
    clip-path: polygon(0 0, 200px 200px, 0 200px);
}
#right-triangle {
    left: 200px;
    clip-path: polygon(200px 0, 200px 200px, 0 200px);
}
